#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char op;
        long long a, b;
        scanf(" %c", &op);
        scanf("%lld %lld", &a, &b);
        switch (op) {
            case '+':
                printf("%lld\n", a + b);
                break;
            case '-':
                printf("%lld\n", a - b);
                break;
            case '*':
                printf("%lld\n", a * b);
                break;
            case '/':
                if (b == 0) {
                    printf("Error: Division by zero is not allowed.\n");
                } else {
                    printf("%lld\n", a / b);
                }
                break;
            case '%':
                if (b == 0) {
                    printf("Error: Division by zero is not allowed.\n");
                } else {
                    printf("%lld\n", a % b);
                }
                break;
            default:
                printf("Invalid operator! Please use one of the following: +, -, *, /, %\n");
        }
    }
    return 0;
}

