import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            char op = br.readLine().trim().charAt(0);
            StringTokenizer st = new StringTokenizer(br.readLine());
            long a = Long.parseLong(st.nextToken());
            long b = Long.parseLong(st.nextToken());
            switch (op) {
                case '+': sb.append(a + b).append('\n'); break;
                case '-': sb.append(a - b).append('\n'); break;
                case '*': sb.append(a * b).append('\n'); break;
                case '/':
                    if (b == 0) sb.append("Error: Division by zero is not allowed.").append('\n');
                    else sb.append(a / b).append('\n');
                    break;
                case '%':
                    if (b == 0) sb.append("Error: Division by zero is not allowed.").append('\n');
                    else sb.append(a % b).append('\n');
                    break;
                default:
                    sb.append("Invalid operator! Please use one of the following: +, -, *, /, %").append('\n');
            }
        }
        System.out.print(sb.toString());
    }
}

