import sys

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out = []
    idx = 1
    for _ in range(T):
        op = data[idx].strip()
        idx += 1
        a_str, b_str = data[idx].split()
        idx += 1
        a = int(a_str)
        b = int(b_str)
        if op == '+':
            out.append(str(a + b))
        elif op == '-':
            out.append(str(a - b))
        elif op == '*':
            out.append(str(a * b))
        elif op == '/':
            if b == 0:
                out.append('Error: Division by zero is not allowed.')
            else:
                out.append(str(int(a / b)))  # truncates toward zero
        elif op == '%':
            if b == 0:
                out.append('Error: Division by zero is not allowed.')
            else:
                out.append(str(a % b))
        else:
            out.append('Invalid operator! Please use one of the following: +, -, *, /, %')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

